/**
 * SERVICE_TURNAROUND — how long each catalog service takes, so the campaign builder can quote an
 * honest "live in about X" estimate BEFORE the owner ships. OWNER-REVIEWABLE: these become a delivery
 * promise to the restaurant, so they are hand-authored (like prices + volume rates), not computed
 * from labor hours (hours are concurrent work, not calendar turnaround — the real clock is dominated
 * by shoot scheduling, owner approval, and external gates like Google verification).
 *
 * Hand-authored side-map keyed by serviceId — NOT in catalog.generated.ts (autogenerated from the DB,
 * would be overwritten). Same pattern as [[service-channels]] / volume-rates. All durations are in
 * BUSINESS DAYS (the unit owners feel). Three classes:
 *   - setup     one-time, a fixed window; may carry an external GATE (out of Apnosh's hands).
 *   - creative  needs a shoot / drafts / the owner's approval → a min-max range; flag needsShoot.
 *   - recurring runs continuously; the only timeline question is "starts within X", then a cadence.
 *
 * The aggregator (aggregate-golive.ts) reads this to compute a go-live RANGE as a critical PATH
 * (setup + creative run in parallel), never a sum. Edit any number here; owner/ops sign-off pending.
 */

export type TurnaroundGate = {
  kind: 'gbp-verify' | 'listing-propagation' | 'pos-vendor' | 'sms-10dlc' | 'print' | 'external'
  /** extra business days the gate can add, on top of Apnosh's own work window. */
  addDays: { min: number; max: number }
  /** plain owner-facing note naming the dependency. */
  note: string
}

export type ServiceTurnaround =
  | { class: 'setup'; business: { min: number; max: number }; gate?: TurnaroundGate }
  | { class: 'creative'; business: { min: number; max: number }; needsShoot?: boolean; shootLeadDays?: { min: number; max: number } }
  | { class: 'recurring'; startsWithin: { min: number; max: number }; cadence: 'weekly' | 'monthly' | 'continuous' }

const GBP_VERIFY: TurnaroundGate = { kind: 'gbp-verify', addDays: { min: 1, max: 7 }, note: 'Google verifies your profile, which can add a few days.' }
const LISTING_PROP: TurnaroundGate = { kind: 'listing-propagation', addDays: { min: 3, max: 7 }, note: 'Listings can take up to a week to show everywhere.' }
const POS_VENDOR: TurnaroundGate = { kind: 'pos-vendor', addDays: { min: 2, max: 7 }, note: 'Timing depends on your ordering / POS vendor.' }
const SMS_10DLC: TurnaroundGate = { kind: 'sms-10dlc', addDays: { min: 3, max: 14 }, note: 'Carrier registration for texting can take 1-2 weeks.' }
const PRINT: TurnaroundGate = { kind: 'print', addDays: { min: 3, max: 7 }, note: 'Printed cards/QRs are produced and shipped.' }

