/** Per content-piece-type production window (business days), used for the creative critical path. */
export const CONTENT_TURNAROUND: Record<string, { min: number; max: number; needsShoot: boolean }> = {
  reel: { min: 7, max: 10, needsShoot: true },
  video: { min: 7, max: 10, needsShoot: true },
  photo: { min: 5, max: 7, needsShoot: true },
  story: { min: 2, max: 4, needsShoot: false },
  post: { min: 2, max: 4, needsShoot: false },
  carousel: { min: 3, max: 5, needsShoot: false },
  graphic: { min: 3, max: 5, needsShoot: false },
  email: { min: 1, max: 3, needsShoot: false },
  sms: { min: 1, max: 3, needsShoot: false },
}
const CONTENT_DEFAULT = { min: 3, max: 5, needsShoot: false }

export function contentTurnaround(type: string) {
  return CONTENT_TURNAROUND[type] ?? CONTENT_DEFAULT
}

export function turnaroundFor(serviceId: string): ServiceTurnaround | undefined {
  return SERVICE_TURNAROUND[serviceId]
}

/** Plain-language ETA label derived from the turnaround, replacing the old hardcoded "~1 week". */
export function etaLabelFor(serviceId: string): string {
  const t = SERVICE_TURNAROUND[serviceId]
  if (!t) return '~1 week'
  if (t.class === 'recurring') return `starts in ${t.startsWithin.min}-${t.startsWithin.max} days`
  const b = t.business
  const lo = t.class === 'creative' && t.needsShoot && t.shootLeadDays ? b.min + t.shootLeadDays.min : b.min
  const hi = t.class === 'creative' && t.needsShoot && t.shootLeadDays ? b.max + t.shootLeadDays.max : b.max
  return `${lo}-${hi} days`
}

// Coverage guard (dev only): every catalog service should have a turnaround so the go-live estimate
// never silently treats a service as zero-time. Mirrors the margin-floor warn loop in priced-catalog.
if (process.env.NODE_ENV !== 'production') {
  void (async () => {
    try {
      const { GENERATED_CATALOG } = await import('./catalog.generated')
      for (const s of GENERATED_CATALOG) {
        if (!SERVICE_TURNAROUND[s.id]) console.warn(`[turnaround] missing turnaround for service: ${s.id}`)
      }
    } catch { /* generated catalog not available in this context */ }
  })()
}
